export function createId() {
    if (window.crypto && typeof window.crypto.randomUUID === "function") {
        return window.crypto.randomUUID();
    }

    return `sg-${Date.now()}-${Math.random().toString(16).slice(2)}`;
}

export function clone(value) {
    return JSON.parse(JSON.stringify(value));
}

export function parseDate(value) {
    if (!value) {
        return null;
    }

    const date = new Date(`${value}T00:00:00`);
    return Number.isNaN(date.getTime()) ? null : date;
}

export function startOfDay(date) {
    const copy = new Date(date);
    copy.setHours(0, 0, 0, 0);
    return copy;
}

export function toInputDate(date) {
    return date.toISOString().slice(0, 10);
}

export function addDays(date, amount) {
    const copy = startOfDay(date);
    copy.setDate(copy.getDate() + amount);
    return toInputDate(copy);
}

export function diffDays(a, b) {
    return Math.round((startOfDay(b) - startOfDay(a)) / 86400000);
}

export function advanceCycle(date, cycle) {
    const copy = new Date(date);

    switch (cycle) {
        case "weekly":
            copy.setDate(copy.getDate() + 7);
            break;
        case "quarterly":
            copy.setMonth(copy.getMonth() + 3);
            break;
        case "yearly":
            copy.setFullYear(copy.getFullYear() + 1);
            break;
        default:
            copy.setMonth(copy.getMonth() + 1);
            break;
    }

    return copy;
}

export function cycleLabel(cycle) {
    const labels = {
        weekly: "Woechentlich",
        monthly: "Monatlich",
        quarterly: "Quartalsweise",
        yearly: "Jaehrlich"
    };

    return labels[cycle] || cycle;
}

export function formatDate(value) {
    const date = parseDate(value);
    return date ? date.toLocaleDateString("de-DE") : "-";
}

export function formatCurrency(amount, currency) {
    return new Intl.NumberFormat("de-DE", {
        style: "currency",
        currency
    }).format(amount || 0);
}

export function roundCurrency(value) {
    return Math.round((value + Number.EPSILON) * 100) / 100;
}

export function sum(values) {
    return roundCurrency(values.reduce((total, value) => total + value, 0));
}

export function severityWeight(value) {
    if (value === "danger") {
        return 3;
    }

    if (value === "warning") {
        return 2;
    }

    return 1;
}

export function csvEscape(value) {
    const stringValue = String(value);

    if (/[",\n]/.test(stringValue)) {
        return `"${stringValue.replace(/"/g, '""')}"`;
    }

    return stringValue;
}

export function parseCsv(text) {
    const rows = [];
    let row = [];
    let current = "";
    let inQuotes = false;

    for (let i = 0; i < text.length; i++) {
        const char = text[i];
        const next = text[i + 1];

        if (char === '"' && inQuotes && next === '"') {
            current += '"';
            i += 1;
        } else if (char === '"') {
            inQuotes = !inQuotes;
        } else if (char === "," && !inQuotes) {
            row.push(current);
            current = "";
        } else if ((char === "\n" || char === "\r") && !inQuotes) {
            if (char === "\r" && next === "\n") {
                i += 1;
            }

            row.push(current);
            if (row.some((value) => value.length > 0)) {
                rows.push(row);
            }

            row = [];
            current = "";
        } else {
            current += char;
        }
    }

    if (current.length > 0 || row.length > 0) {
        row.push(current);
        rows.push(row);
    }

    return rows;
}

export function downloadFile(content, filename, type) {
    const blob = new Blob([content], { type });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = filename;
    link.click();
    URL.revokeObjectURL(url);
}

import { STORAGE_KEY } from "../constants.js";
import { clone } from "../utils.js";
import { loadLocalState, sanitizeState, saveLocalState } from "./localRepository.js";

export function createDataSource(options = {}) {
    const mode = options.mode || "local";

    if (mode === "remote") {
        return createRemoteDataSource(options.baseUrl || "");
    }

    return createLocalDataSource();
}

function createLocalDataSource() {
    let state = loadLocalState(STORAGE_KEY);

    return {
        async getState() {
            return clone(state);
        },

        async importState(nextState) {
            state = sanitizeState(nextState);
            saveLocalState(STORAGE_KEY, state);
            return clone(state);
        },

        async replaceSubscriptions(subscriptions) {
            state.subscriptions = clone(subscriptions);
            saveLocalState(STORAGE_KEY, state);
            return clone(state);
        },

        async saveSubscription(subscription) {
            const index = state.subscriptions.findIndex((item) => item.id === subscription.id);

            if (index >= 0) {
                state.subscriptions[index] = clone(subscription);
            } else {
                state.subscriptions.unshift(clone(subscription));
            }

            saveLocalState(STORAGE_KEY, state);
            return clone(subscription);
        },

        async deleteSubscription(id) {
            state.subscriptions = state.subscriptions.filter((item) => item.id !== id);
            saveLocalState(STORAGE_KEY, state);
        },

        async saveSettings(settings) {
            state.settings = clone(settings);
            saveLocalState(STORAGE_KEY, state);
            return clone(settings);
        },

        async clearAll() {
            state = sanitizeState({});
            saveLocalState(STORAGE_KEY, state);
            return clone(state);
        }
    };
}

function createRemoteDataSource(baseUrl) {
    return {
        async getState() {
            const response = await fetch(`${baseUrl}/state`);
            return response.json();
        },

        async importState(nextState) {
            const response = await fetch(`${baseUrl}/state/import`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(nextState)
            });
            return response.json();
        },

        async replaceSubscriptions(subscriptions) {
            const response = await fetch(`${baseUrl}/subscriptions/replace`, {
                method: "PUT",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ subscriptions })
            });
            return response.json();
        },

        async saveSubscription(subscription) {
            const method = subscription.id ? "PUT" : "POST";
            const url = subscription.id ? `${baseUrl}/subscriptions/${subscription.id}` : `${baseUrl}/subscriptions`;
            const response = await fetch(url, {
                method,
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(subscription)
            });
            return response.json();
        },

        async deleteSubscription(id) {
            await fetch(`${baseUrl}/subscriptions/${id}`, { method: "DELETE" });
        },

        async saveSettings(settings) {
            const response = await fetch(`${baseUrl}/settings`, {
                method: "PUT",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(settings)
            });
            return response.json();
        },

        async clearAll() {
            const response = await fetch(`${baseUrl}/state`, { method: "DELETE" });
            return response.json();
        }
    };
}

import { DEFAULT_STATE } from "../constants.js";
import { clone, createId, toInputDate } from "../utils.js";

export function loadLocalState(storageKey) {
    try {
        const stored = localStorage.getItem(storageKey);
        if (!stored) {
            return clone(DEFAULT_STATE);
        }

        return sanitizeState(JSON.parse(stored));
    } catch {
        return clone(DEFAULT_STATE);
    }
}

export function saveLocalState(storageKey, state) {
    localStorage.setItem(storageKey, JSON.stringify(state));
}

export function sanitizeState(raw) {
    const safe = clone(DEFAULT_STATE);
    safe.settings.monthlyBudget = Number(raw.settings?.monthlyBudget || 0);
    safe.settings.baseCurrency = raw.settings?.baseCurrency || "EUR";
    safe.settings.exchangeRates = {
        EUR: Number(raw.settings?.exchangeRates?.EUR || 1),
        USD: Number(raw.settings?.exchangeRates?.USD || 0.93),
        GBP: Number(raw.settings?.exchangeRates?.GBP || 1.16),
        CHF: Number(raw.settings?.exchangeRates?.CHF || 1.04)
    };
    safe.subscriptions = Array.isArray(raw.subscriptions)
        ? raw.subscriptions.map((item) => ({
            id: item.id || createId(),
            name: item.name || "Unbenanntes Abo",
            category: item.category || "Sonstiges",
            amount: Number(item.amount || 0),
            currency: item.currency || "EUR",
            cycle: item.cycle || "monthly",
            nextPaymentDate: item.nextPaymentDate || toInputDate(new Date()),
            startDate: item.startDate || "",
            endDate: item.endDate || "",
            cancelDeadline: item.cancelDeadline || "",
            reminderDaysBefore: Number(item.reminderDaysBefore || 7),
            usageCount: Number(item.usageCount || 0),
            valueScore: Number(item.valueScore || 5),
            autoRenew: item.autoRenew !== false && item.autoRenew !== "false",
            active: item.active !== false && item.active !== "false",
            notes: item.notes || ""
        }))
        : [];

    return safe;
}

